"""
Test Cases for Bill of Lading (B/L) Parser - 43 cases
"""
import sys, os, json
sys.path.insert(0, os.path.join(os.path.dirname(os.path.abspath(__file__)), ".."))

from src.parsers.block_bol_parser import parse_bol_block_based
from src.parsers.block_bol_zoomtext_parser import parse_zoom_bol


def run_case(case_id, filename, raw_text, zoom_text):
    bol = parse_bol_block_based(raw_text)
    if zoom_text and zoom_text.strip():
        zoom_lines = zoom_text.splitlines()
        parse_zoom_bol(zoom_lines, bol)
    d = bol.model_dump()
    return d


ALL_FIELDS = [
    # Identification
    "blNumber", "issueDate", "issuePlace",
    # Shipper
    "shipperName", "shipperAddress", "shipperTel",
    # Consignee
    "consigneeName", "consigneeAddress", "consigneeTaxId",
    # Notify Party
    "notifyParty",
    # Carrier / Vessel
    "carrier", "vesselVoyage",
    "portOfLoading", "portOfDischarge",
    "placeOfReceipt", "placeOfDelivery",
    # Container
    "containerNo", "sealNo", "typeOfMovement",
    # Cargo Summary
    "description", "packages", "grossWeight", "netWeight",
    "measurement", "shippingMarks",
    # Freight & Terms
    "freightTerms", "tradeTerm", "lcNumber",
    "numberOfOriginals", "shippedOnBoardDate", "totalContainers",
    # Delivery
    "deliveryAgent",
]


def print_result(case_id, filename, d):
    null_count = sum(1 for f in ALL_FIELDS if d.get(f) is None)
    ok_count = len(ALL_FIELDS) - null_count

    print(f"\n{'='*80}")
    print(f"[{case_id:02d}] {filename}  ({ok_count}/{len(ALL_FIELDS)} fields)")
    print(f"{'='*80}")

    json_output = {k: d.get(k) for k in ALL_FIELDS}
    print(json.dumps(json_output, ensure_ascii=False, indent=2))

    null_fields = [f for f in ALL_FIELDS if d.get(f) is None]
    if null_fields:
        print(f"\n  \u274c NULL: {', '.join(null_fields)}")
    else:
        print(f"\n  \u2705 All fields populated!")

    # ---- ItemList ----
    items = d.get("itemList", []) or []
    item_count = len(items)
    if item_count > 0:
        print(f"\n  \U0001f4e6 itemList: {item_count} items")
        for i, item in enumerate(items[:5]):
            desc = (item.get('description') or '-')[:50]
            hs = item.get('hsCode') or '-'
            gw = item.get('grossWeight', '-')
            meas = item.get('measurement', '-')
            print(f"    [{i+1}] {desc} | hs={hs} | gw={gw} | meas={meas}")
        if item_count > 5:
            print(f"    ... +{item_count - 5} more")
    else:
        print(f"\n  \u26a0\ufe0f  itemList: EMPTY")

    return ok_count, item_count


